import{_ as e,C as n,o as s,c as d,a2 as a,E as i}from"./chunks/framework.BnBoz4Zl.js";const o="/anjian-workbuddy-bluebook-site/assets/001_image_WcJzb4b7Yo.CjjDKNn7.png",r="/anjian-workbuddy-bluebook-site/assets/002_image_M0YFbAywgo.r0hbq5Dq.png",p="/anjian-workbuddy-bluebook-site/assets/003_image_N5i2bw6V5o.Do0TqnKx.png",h="/anjian-workbuddy-bluebook-site/assets/004_image_FiYybAIEQo.FaXvh0ao.png",k="/anjian-workbuddy-bluebook-site/assets/005_image_NaOwbuAcQo.BJB_y8Wz.png",b="/anjian-workbuddy-bluebook-site/assets/006_image_F5Ngb4vd5o.kEX7BI7Q.png",g="/anjian-workbuddy-bluebook-site/assets/007_image_QMdJbhsm0o.cyCI1sZ-.png",c="/anjian-workbuddy-bluebook-site/assets/008_image_D7z7b4DWvo.CdPIvFcD.png",u="/anjian-workbuddy-bluebook-site/assets/009_image_XXrkbXOymo.CoBSqDnr.png",A="/anjian-workbuddy-bluebook-site/assets/010_image_BXYeb8ld7o.c5cNHvbW.png",E="/anjian-workbuddy-bluebook-site/assets/011_image_NwvvbJkuco.CT01GukL.png",_="/anjian-workbuddy-bluebook-site/assets/012_image_LEKGbkn2Go.DyC0FGUm.png",m="/anjian-workbuddy-bluebook-site/assets/013_image_Mp0ZbEmn7o.l7ryVJ_n.png",B="/anjian-workbuddy-bluebook-site/assets/014_image_C1aCbJYz3o.DPNvHf5H.png",S="/anjian-workbuddy-bluebook-site/assets/015_image_MG56bW6jlo.DFlHjZRy.png",q="/anjian-workbuddy-bluebook-site/assets/016_image_HoW7bnRYFo.Cj2k8WqR.png",w=JSON.parse('{"title":"第 22 章 打造skill：将书和视频蒸馏为可执行 Skill","description":"制作skill，除了把自己的SOP沉淀为skill外，给大家推荐一个更简单方便的办法。 可以使用cangjie-skill把知识蒸馏成skill。 cangjie-skill 开源项目（v1 蒸馏书，v2 增加视频蒸馏），以及 Andrej Karpathy 关于 LLM 个人知识库的思路。","frontmatter":{},"headers":[],"relativePath":"bluebook/第三篇 进阶篇：把案例变成自己的工作系统/第 22 章 打造skill：将书和视频蒸馏为可执行 Skill/index.md","filePath":"bluebook/第三篇 进阶篇：把案例变成自己的工作系统/第 22 章 打造skill：将书和视频蒸馏为可执行 Skill/index.md","lastUpdated":1783659790000}'),y={name:"bluebook/第三篇 进阶篇：把案例变成自己的工作系统/第 22 章 打造skill：将书和视频蒸馏为可执行 Skill/index.md"};function x(P,t,v,f,D,j){const l=n("MermaidDiagram");return s(),d("div",null,[t[0]||(t[0]=a('<h1 id="第-22-章-打造skill-将书和视频蒸馏为可执行-skill" tabindex="-1">第 22 章 打造skill：将书和视频蒸馏为可执行 Skill <a class="header-anchor" href="#第-22-章-打造skill-将书和视频蒸馏为可执行-skill" aria-label="Permalink to &quot;第 22 章 打造skill：将书和视频蒸馏为可执行 Skill&quot;">​</a></h1><p>制作skill，除了把自己的SOP沉淀为skill外，给大家推荐一个更简单方便的办法。</p><p>可以使用<a href="https://github.com/kangarooking/cangjie-skill" target="_blank" rel="noreferrer">cangjie-skill</a>把知识蒸馏成skill。</p><p><img src="'+o+'" alt="" loading="lazy"></p><p>cangjie-skill 开源项目（v1 蒸馏书，v2 增加视频蒸馏），以及 Andrej Karpathy 关于 LLM 个人知识库的思路。</p><p>本章回答：如何将书本和视频中的方法论转化为 Agent 可自动调用的 Skill，以及这与 RAG 检索的本质差别在哪里。</p><h2 id="问题起点-知识读了但用不起来" tabindex="-1">问题起点：知识读了但用不起来 <a class="header-anchor" href="#问题起点-知识读了但用不起来" aria-label="Permalink to &quot;问题起点：知识读了但用不起来&quot;">​</a></h2><p>AI 在训练时已经摄入了大量经典著作，但在实际问答中，它往往输出&quot;正确的废话&quot;——每个字都对，但缺乏针对特定问题的可落地步骤。这不是幻觉问题，而是调用机制问题：AI 知道书里有什么，但不知道该在什么场景下主动调出哪个框架。</p><p>人类读者面临同样的问题。读完一本书，笔记做了、金句划了，合上书以为升级了。两周后遇到真实问题，那些方法论却抓不住。知识在记忆里，但激活路径不清晰。</p><p>知识精馏要解决的，就是这个&quot;学了用不上&quot;的问题。</p><p><img src="'+r+'" alt="" loading="lazy"></p><h2 id="知识精馏的定义" tabindex="-1">知识精馏的定义 <a class="header-anchor" href="#知识精馏的定义" aria-label="Permalink to &quot;知识精馏的定义&quot;">​</a></h2><p>知识精馏（Knowledge Distillation for Skills）是指：从书本或视频中，提取出具有独立触发条件和执行步骤的原子化知识单元（Skill），使 Agent 在遇到对应场景时能够自动激活并给出可落地的行动路径。</p><p>化学中的精馏是按沸点将混合物分离成不同纯净组分。知识精馏按&quot;框架 / 原则 / 案例 / 反例 / 术语&quot;五个维度，将书或视频中的知识分离成不同类型的纯净组分，然后只把真正有用的提纯成可执行的 Skill。</p><p>知识精馏不是：</p><ul><li>摘要（压缩原文）</li><li>读书笔记（结构化原文）</li><li>RAG 索引（存储原文片段供检索）</li></ul><p>知识精馏是：将方法论转化为 Agent 能够在真实场景下自动调用的执行单元。</p><h2 id="六阶段蒸馏-sop" tabindex="-1">六阶段蒸馏 SOP <a class="header-anchor" href="#六阶段蒸馏-sop" aria-label="Permalink to &quot;六阶段蒸馏 SOP&quot;">​</a></h2><p>cangjie-skill 使用六个阶段将一本书或一组视频蒸馏成一套 Skill。</p>',19)),i(l,{graph:"flowchart%20TD%0A%20%20%20%20A%5B%E9%98%B6%E6%AE%B5%200%EF%BC%9A%E6%95%B4%E4%B9%A6%2F%E6%95%B4%E7%89%87%E7%90%86%E8%A7%A3%5D%20--%3E%20B%5B%E9%98%B6%E6%AE%B5%201%EF%BC%9A%E4%BA%94%E4%B8%AA%20Agent%20%E5%B9%B6%E8%A1%8C%E6%8F%90%E5%8F%96%5D%0A%20%20%20%20B%20--%3E%20C%5B%E9%98%B6%E6%AE%B5%202%EF%BC%9A%E4%B8%89%E9%87%8D%E9%AA%8C%E8%AF%81%E7%AD%9B%E9%80%89%5D%0A%20%20%20%20C%20--%3E%20D%5B%E9%98%B6%E6%AE%B5%203%EF%BC%9A%E6%9E%84%E9%80%A0%20Skill%5D%0A%20%20%20%20D%20--%3E%20E%5B%E9%98%B6%E6%AE%B5%204%EF%BC%9A%E9%93%BE%E6%8E%A5%E2%80%94%E2%80%94%E5%BB%BA%E7%AB%8B%20Skill%20%E5%85%B3%E7%B3%BB%E7%BD%91%E7%BB%9C%5D%0A%20%20%20%20E%20--%3E%20F%5B%E9%98%B6%E6%AE%B5%205%EF%BC%9A%E5%8E%8B%E5%8A%9B%E6%B5%8B%E8%AF%95%5D%0A"}),t[1]||(t[1]=a('<p><img src="'+p+'" alt="" loading="lazy"></p><p><img src="'+h+'" alt="" loading="lazy"></p><p>以蒸馏《文案创作完全手册》为例</p><p><img src="'+k+'" alt="" loading="lazy"></p><h3 id="阶段-0-整书-整片理解" tabindex="-1">阶段 0：整书 / 整片理解 <a class="header-anchor" href="#阶段-0-整书-整片理解" aria-label="Permalink to &quot;阶段 0：整书 / 整片理解&quot;">​</a></h3><p>不从摘取金句开始，而是先读清整本书的骨架：</p><ul><li>全书主旨是什么；</li><li>核心论证链怎么走；</li><li>关键术语作者如何定义和使用；</li><li>作者自身的局限与盲点在哪里。</li></ul><p>这一步决定后续提取的质量上限。跳过这一步直接提取，容易把作者反对的观点当成他支持的方法论。</p><p><img src="'+b+'" alt="" loading="lazy"></p><h3 id="阶段-1-五个-agent-并行提取" tabindex="-1">阶段 1：五个 Agent 并行提取 <a class="header-anchor" href="#阶段-1-五个-agent-并行提取" aria-label="Permalink to &quot;阶段 1：五个 Agent 并行提取&quot;">​</a></h3><p>五个 Agent 同时从五个维度扫描全文，独立工作，互不干扰：</p><table tabindex="0"><thead><tr><th>Agent</th><th>提取目标</th></tr></thead><tbody><tr><td>框架提取 Agent</td><td>作者构建的分析或决策框架</td></tr><tr><td>原则提取 Agent</td><td>可跨场景复用的行为原则</td></tr><tr><td>案例提取 Agent</td><td>作者援引的正面案例和成功路径</td></tr><tr><td>反例提取 Agent</td><td>作者援引的失败案例和反面教训</td></tr><tr><td>术语词典 Agent</td><td>作者专有术语及其定义</td></tr></tbody></table><p>五个角度并行，避免单线阅读中的视角遗漏。</p><p><img src="'+g+'" alt="" loading="lazy"></p><h3 id="阶段-1-5-三重验证筛选" tabindex="-1">阶段 1.5：三重验证筛选 <a class="header-anchor" href="#阶段-1-5-三重验证筛选" aria-label="Permalink to &quot;阶段 1.5：三重验证筛选&quot;">​</a></h3><p>每个候选知识单元必须通过三关，未通过直接淘汰：</p><table tabindex="0"><thead><tr><th>验证类型</th><th>检查内容</th></tr></thead><tbody><tr><td>跨域验证</td><td>该方法论在书中至少两个独立场景出现过，不是孤证</td></tr><tr><td>预测力测试</td><td>能用它推导出书中没有直接讨论的问题吗</td></tr><tr><td>独特性检验</td><td>是不是任何人都能说出来的常识？常识不构成 Skill</td></tr></tbody></table><p>宁缺毋滥。一本书通常有 50–100 个候选单元，通过三重验证后保留 10–25 个。</p><p><img src="'+c+'" alt="" loading="lazy"></p><h3 id="阶段-2-构造-skill" tabindex="-1">阶段 2：构造 Skill <a class="header-anchor" href="#阶段-2-构造-skill" aria-label="Permalink to &quot;阶段 2：构造 Skill&quot;">​</a></h3><p>每个通过验证的知识单元被构造成一个 Skill，核心是设计触发条件：</p><ul><li>什么场景下自动激活；</li><li>激活后执行什么步骤；</li><li>什么时候不该用（边界）；</li><li>质量验证标准是什么。</li></ul><p>触发条件的设计是最难也最关键的一步。没有触发条件的 Skill，在实际使用中无法被 Agent 正确识别和调用。</p><p><img src="'+u+'" alt="" loading="lazy"></p><h3 id="阶段-4-链接" tabindex="-1">阶段 4：链接 <a class="header-anchor" href="#阶段-4-链接" aria-label="Permalink to &quot;阶段 4：链接&quot;">​</a></h3><p>找出 Skill 之间的关系，形成知识网络：</p><ul><li><strong>依赖</strong>：Skill A 的执行需要先调用 Skill B 的输出；</li><li><strong>对比</strong>：Skill A 和 Skill B 适用于相似场景但方向相反；</li><li><strong>组合</strong>：Skill A 和 Skill C 联合使用效果更好。</li></ul><p>链接层让 Agent 在遇到复杂问题时，能够选择一组 Skill 而不只是单个 Skill。</p><p><img src="'+A+'" alt="" loading="lazy"></p><h3 id="阶段-5-压力测试" tabindex="-1">阶段 5：压力测试 <a class="header-anchor" href="#阶段-5-压力测试" aria-label="Permalink to &quot;阶段 5：压力测试&quot;">​</a></h3><p><strong>诱饵测试</strong>：故意给不该触发的场景，检验 Skill 是否能忍住不激活。一个没有边界的 Skill，在错误场景下调用反而帮倒忙。</p><p><strong>执行验证</strong>：给出真实问题，验证 Skill 是否能输出可落地的步骤而不是正确的废话。</p><p><img src="'+E+'" alt="" loading="lazy"></p><h2 id="蒸馏产物结构" tabindex="-1">蒸馏产物结构 <a class="header-anchor" href="#蒸馏产物结构" aria-label="Permalink to &quot;蒸馏产物结构&quot;">​</a></h2><p>一本书蒸馏完成后，产物是一套 Skill 集合：</p><p><img src="'+_+`" alt="" loading="lazy"></p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>book-skill/</span></span>
<span class="line"><span>├── README.md               # 书目信息、蒸馏说明、适用场景</span></span>
<span class="line"><span>├── skills/</span></span>
<span class="line"><span>│   ├── skill-01.md         # 每个 Skill 独立文件</span></span>
<span class="line"><span>│   ├── skill-02.md</span></span>
<span class="line"><span>│   └── ...</span></span>
<span class="line"><span>├── index.md                # Skill 关系网络（链接层产物）</span></span>
<span class="line"><span>└── tests/</span></span>
<span class="line"><span>    ├── skill-01-test.md    # 每个 Skill 的测试用例</span></span>
<span class="line"><span>    └── ...</span></span></code></pre></div><p>每个 Skill 文件包含：触发条件、执行步骤、输出格式、边界限制、测试用例。测试用例格式兼容 darwin-skill（自动 Skill 进化工具），蒸馏产物可以持续自动优化。</p><p><img src="`+m+'" alt="" loading="lazy"></p><p><img src="'+B+'" alt="" loading="lazy"></p><h2 id="知识精馏-vs-rag" tabindex="-1">知识精馏 vs RAG <a class="header-anchor" href="#知识精馏-vs-rag" aria-label="Permalink to &quot;知识精馏 vs RAG&quot;">​</a></h2><p>这是使用者最常问的问题。</p><table tabindex="0"><thead><tr><th>维度</th><th>RAG</th><th>知识精馏（Skill）</th></tr></thead><tbody><tr><td>本质</td><td>检索——找出最相关的原文片段</td><td>提炼——从原文中提取可执行的方法论</td></tr><tr><td>使用前提</td><td>用户需要知道该问什么</td><td>用户描述问题，Skill 自动识别并激活</td></tr><tr><td>质量控制</td><td>无——任何内容都可以入库</td><td>三重验证过滤，宁缺毋滥</td></tr><tr><td>调用方式</td><td>被动等待查询</td><td>主动匹配场景并触发</td></tr><tr><td>知识形态</td><td>存储原文（记住知识）</td><td>提纯为执行步骤（运用知识）</td></tr><tr><td>边界控制</td><td>无</td><td>诱饵测试确保不乱激活</td></tr><tr><td>资源消耗</td><td>较重（需维护向量索引）</td><td>较轻（Skill 文件即可）</td></tr></tbody></table><p>RAG 解决&quot;知识管理&quot;问题——让你能查到书里有什么。知识精馏解决&quot;知识运用&quot;问题——让 Agent 在对的时刻主动拿出对的框架。</p><p>当你不知道该问什么时，RAG 帮不了你。Skill 不需要你记得书里有哪些方法论。</p><h2 id="与-karpathy-llm-wiki-思路的对比" tabindex="-1">与 Karpathy LLM Wiki 思路的对比 <a class="header-anchor" href="#与-karpathy-llm-wiki-思路的对比" aria-label="Permalink to &quot;与 Karpathy LLM Wiki 思路的对比&quot;">​</a></h2><p>Andrej Karpathy 提出 LLM 知识库（LLM Wiki）的思路：将原始资料索引到目录，让 LLM 编译成 Wiki，然后对 Wiki 做 Q&amp;A，产出结果再回填，持续增强。</p><p>cangjie-skill 的阶段 0（整书理解）和阶段 1（并行提取）吸收了这一核心思想：先让 AI 深度阅读、结构化整理、建立索引、维护一致性。</p><p>两者的差别在于最后几步：</p><table tabindex="0"><thead><tr><th>对比点</th><th>LLM Wiki</th><th>知识精馏</th></tr></thead><tbody><tr><td>产物形态</td><td>Wiki 条目（结构化知识库）</td><td>Skill 集合（可执行单元）</td></tr><tr><td>使用方式</td><td>用户主动查询</td><td>Agent 被动触发后主动激活</td></tr><tr><td>解决问题</td><td>知识管理</td><td>知识运用</td></tr></tbody></table><p>两种方案不互斥，但目标不同。</p><h2 id="视频蒸馏工作流-v2-新增" tabindex="-1">视频蒸馏工作流（v2 新增） <a class="header-anchor" href="#视频蒸馏工作流-v2-新增" aria-label="Permalink to &quot;视频蒸馏工作流（v2 新增）&quot;">​</a></h2><p>cangjie-skill v2 在书本蒸馏基础上增加了视频蒸馏能力（借助<a href="https://github.com/kangarooking/kangarooking-skills/tree/main/video-downloader" target="_blank" rel="noreferrer">video-downloader skill</a>）。视频与书的区别在于：需要先完成&quot;视频 → 文字&quot;的转换，再进入六阶段 SOP。</p><p><img src="'+S+'" alt="" loading="lazy"></p><h3 id="视频获取与转写" tabindex="-1">视频获取与转写 <a class="header-anchor" href="#视频获取与转写" aria-label="Permalink to &quot;视频获取与转写&quot;">​</a></h3><p>整体流程：</p>',56)),i(l,{graph:"flowchart%20LR%0A%20%20%20%20A%5B%E8%BE%93%E5%85%A5%E8%A7%86%E9%A2%91%E9%93%BE%E6%8E%A5%5D%20--%3E%20B%5Bvideo-downloader%20skill%EF%BC%9A%E4%B8%8B%E8%BD%BD%E8%A7%86%E9%A2%91%5D%0A%20%20%20%20B%20--%3E%20C%5B%E6%8F%90%E5%8F%96%E9%9F%B3%E9%A2%91%5D%0A%20%20%20%20C%20--%3E%20D%5BASR%20%E8%BD%AC%E5%86%99%E4%B8%BA%E6%96%87%E6%A1%88%5D%0A%20%20%20%20D%20--%3E%20E%5Bcangjie-skill%EF%BC%9A%E5%85%AD%E9%98%B6%E6%AE%B5%E8%92%B8%E9%A6%8F%5D%0A%20%20%20%20E%20--%3E%20F%5B%E8%BE%93%E5%87%BA%20Skill%20%E9%9B%86%E5%90%88%5D%0A"}),t[2]||(t[2]=a(`<p><strong>视频下载</strong>：使用 yt-dlp（开源工具）支持 YouTube、B 站等主流平台，只需输入视频链接即可自动下载。视频号因平台限制暂不支持自动化。</p><p><strong>音频转写</strong>：本地 Whisper 模型可用，但长视频转写耗时显著（一小时视频约需 48 分钟本地转写）。推荐使用 ASR API 服务，速度快，适合批量处理。</p><h3 id="多视频合并蒸馏" tabindex="-1">多视频合并蒸馏 <a class="header-anchor" href="#多视频合并蒸馏" aria-label="Permalink to &quot;多视频合并蒸馏&quot;">​</a></h3><p>同一主题的多个视频可以合并蒸馏，产出统一的 Skill 集合。合并时 Agent 自动处理内容去重和知识单元合并，避免同一原则在不同视频中被重复提取为多个 Skill。</p><h3 id="video-downloader-skill-与-cangjie-skill-的分工" tabindex="-1">video-downloader skill 与 cangjie-skill 的分工 <a class="header-anchor" href="#video-downloader-skill-与-cangjie-skill-的分工" aria-label="Permalink to &quot;video-downloader skill 与 cangjie-skill 的分工&quot;">​</a></h3><p>视频处理逻辑（下载、提取音频、转写）独立封装在 video-downloader skill 中，不集成到 cangjie-skill 内部。原因是职责分离：cangjie-skill 专注文本蒸馏，视频获取是前置准备步骤，两者可以独立演进。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>使用方式：</span></span>
<span class="line"><span>1. 用 video-downloader skill 获取视频文案</span></span>
<span class="line"><span>2. 将文案交给 cangjie-skill 进行六阶段蒸馏</span></span>
<span class="line"><span>3. 输出对应的 Skill 集合</span></span></code></pre></div><h2 id="适用与不适用场景" tabindex="-1">适用与不适用场景 <a class="header-anchor" href="#适用与不适用场景" aria-label="Permalink to &quot;适用与不适用场景&quot;">​</a></h2><h3 id="适合蒸馏的材料" tabindex="-1">适合蒸馏的材料 <a class="header-anchor" href="#适合蒸馏的材料" aria-label="Permalink to &quot;适合蒸馏的材料&quot;">​</a></h3><table tabindex="0"><thead><tr><th>类型</th><th>适合程度</th><th>说明</th></tr></thead><tbody><tr><td>方法论密度高的书</td><td>★★★★★</td><td>框架清晰，原则可提取，最适合</td></tr><tr><td>访谈 / 课程视频</td><td>★★★★☆</td><td>内容结构化程度较高，适合蒸馏</td></tr><tr><td>长视频 / 播客</td><td>★★★☆☆</td><td>可用，知识密度因内容而异</td></tr><tr><td>金句散文类书籍</td><td>★★☆☆☆</td><td>方法论少，蒸馏产物质量有限</td></tr><tr><td>小说 / 叙事文学</td><td>★☆☆☆☆</td><td>不适合，缺乏可提取的方法论框架</td></tr></tbody></table><h3 id="蒸馏的前置条件" tabindex="-1">蒸馏的前置条件 <a class="header-anchor" href="#蒸馏的前置条件" aria-label="Permalink to &quot;蒸馏的前置条件&quot;">​</a></h3><p>蒸馏前最好读过或看过一遍原材料。原因：</p><ul><li>需要判断哪些方法论是重点；</li><li>需要在蒸馏过程中的关键节点做判断（如三重验证的边界情况）；</li><li>读过之后蒸馏，吸收率显著高于未读过直接蒸馏。</li></ul><p>蒸馏不是替代阅读，而是阅读后的知识结构化工具。</p><h2 id="蒸馏产物的持续优化" tabindex="-1">蒸馏产物的持续优化 <a class="header-anchor" href="#蒸馏产物的持续优化" aria-label="Permalink to &quot;蒸馏产物的持续优化&quot;">​</a></h2><p>cangjie-skill 产出的每个 Skill 自带测试用例，格式兼容 darwin-skill（达尔文.Skill）。</p><p>darwin-skill 是自动 Skill 进化工具：将 Skill 喂给它，它会自动评估、改进、测试，且分数只升不降。</p><p>这意味着蒸馏产物不是静态的。随着 Agent 实际使用反馈的积累，Skill 可以持续自动优化，逐步接近书中方法论在真实场景下的最优表达。</p><h2 id="资源消耗与模型选择" tabindex="-1">资源消耗与模型选择 <a class="header-anchor" href="#资源消耗与模型选择" aria-label="Permalink to &quot;资源消耗与模型选择&quot;">​</a></h2><p>知识精馏是 Token 消耗密集型任务，主要来源于：</p><ul><li>阶段 0 的全书上下文理解（长上下文）；</li><li>阶段 1 的五个 Agent 并行调用；</li><li>阶段 2 的三重验证（多轮推理）；</li><li>阶段 5 的压力测试（多组测试用例）。</li></ul><table tabindex="0"><thead><tr><th>场景</th><th>大致 Token 消耗</th><th>大致耗时参考</th></tr></thead><tbody><tr><td>蒸馏一本普通书</td><td>数万至十余万 Token</td><td>30–90 分钟</td></tr><tr><td>蒸馏 26 集课程视频（4 小时）</td><td>较高</td><td>约 1 小时</td></tr><tr><td>蒸馏 4 个主题视频（80 分钟）</td><td>中等</td><td>约 40 分钟</td></tr></tbody></table><p><strong>模型选择建议</strong>：</p><ul><li>任务拆解和蒸馏协调：使用推理能力强的模型负责 Agent 编排；</li><li>并行提取和验证：可使用性价比高的 Coding 模型执行；</li><li>长上下文场景：选择原生支持长上下文的模型，避免因上下文截断导致蒸馏不完整。</li></ul><p>【图片占位：Token 消耗过程截图，展示蒸馏过程中 Token 使用量的增长曲线】</p><h2 id="蒸馏产物的分享与复用" tabindex="-1">蒸馏产物的分享与复用 <a class="header-anchor" href="#蒸馏产物的分享与复用" aria-label="Permalink to &quot;蒸馏产物的分享与复用&quot;">​</a></h2><p>知识精馏的一个重要特点是：产物（Skill 集合）可以直接分享和复用。</p><p><strong>使用已蒸馏的 Skill</strong>：将 GitHub 仓库地址提供给 Agent，让 Agent 自动安装对应 Skill 即可使用，无需重新蒸馏。</p><p><strong>社区协作</strong>：同一本书不需要被每个人重复蒸馏。任何人蒸馏的成果都可以开源，其他人直接复用。</p><p><strong>扩展应用</strong>：视频课程的蒸馏产物可以进一步构建课程 Agent，供学员问答和辅助实践，即课程内容的结构化知识服务化。</p><h2 id="常见误区" tabindex="-1">常见误区 <a class="header-anchor" href="#常见误区" aria-label="Permalink to &quot;常见误区&quot;">​</a></h2><p><strong>误区 1：AI 训练过的书不需要再蒸馏</strong></p><p>对于大众熟知的经典书籍，AI 确实有一定记忆。但对小众书籍、新出版书籍以及时效性强的视频内容，AI 大概率没有训练过。此外，即使 AI 训练过某本书，蒸馏的价值在于建立触发条件——让 AI 知道在什么场景下应该调出该书的哪个框架，而不只是&quot;知道书里有什么&quot;。</p><p><strong>误区 2：蒸馏完就不需要看书了</strong></p><p>蒸馏是阅读的补充，不是替代。没读过就蒸馏，会在关键判断节点上缺乏背景，导致蒸馏结果遗漏重点。阅读过一遍后再蒸馏，蒸馏产物的质量和完整度显著更高。</p><p><strong>误区 3：AI 给了建议就能直接执行</strong></p><p>即使 Skill 被正确激活并给出了可落地的步骤，方向对不对、能不能执行、效果好不好，仍然需要人来判断。AI 给出的是选项和分析，决策是人的责任。</p><p><strong>误区 4：Skill 覆盖越多越好</strong></p><p>覆盖太宽的触发条件会导致 Skill 在不适用的场景下被错误激活，反而产生误导。三重验证和诱饵测试的目的正是控制边界，宁可覆盖窄一点，也不要乱激活。</p><h2 id="蒸馏结果示例" tabindex="-1">蒸馏结果示例 <a class="header-anchor" href="#蒸馏结果示例" aria-label="Permalink to &quot;蒸馏结果示例&quot;">​</a></h2><p>以吴恩达《给所有人的 AI 入门课》（2026 版，26 个视频，时长约 4 小时）为例：</p><ul><li>蒸馏耗时：约 1 小时</li><li>产出：25 个 Skill</li><li>特点：全部为时效性内容，AI 未经训练，蒸馏后可直接在对应场景下被 Agent 调用</li></ul><p><img src="`+q+'" alt="" loading="lazy"></p><h2 id="总结-知识精馏在技能包体系中的位置" tabindex="-1">总结：知识精馏在技能包体系中的位置 <a class="header-anchor" href="#总结-知识精馏在技能包体系中的位置" aria-label="Permalink to &quot;总结：知识精馏在技能包体系中的位置&quot;">​</a></h2><p>知识精馏是 Skill 的一种生产方式。它和第 25 章讨论的 SOP → Skill 封装流程是并行的：</p><table tabindex="0"><thead><tr><th>来源</th><th>适用场景</th></tr></thead><tbody><tr><td>从业务流程提炼（SOP → Skill）</td><td>企业内部操作规范、重复性业务流程</td></tr><tr><td>从书本 / 视频蒸馏（知识精馏）</td><td>专家方法论、经典著作、高价值课程内容</td></tr></tbody></table><p>两者产物格式一致，都是带有触发条件的可执行 Skill，可以在同一个 Agent 框架下混合使用。</p>',47))])}const F=e(y,[["render",x]]);export{w as __pageData,F as default};
